#include <string>
#include <unordered_map>

class Solution {
public:
    int repeatedStringMatch(std::string a, std::string b) {
        int count = 0;
        std::unordered_map<char, int> charCount;

        for (char c : a) {
            charCount[c]++;
        }

        for (char c : b) {
            if (charCount[c] > 0) {
                charCount[c]--;
                count += charCount[c];
            }
        }

        if (count < 0) {
            return -1;
        }

        return count;
    }
};
```

